import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import { Clock, User } from 'lucide-react';
import { Product } from '../types';
import { formatDistanceToNow } from 'date-fns';
import { ko } from 'date-fns/locale';

interface ProductCardProps {
  product: Product;
}

export const ProductCard: React.FC<ProductCardProps> = ({ product }) => {
  const [timeLeft, setTimeLeft] = useState<string>('');

  useEffect(() => {
    const updateTime = () => {
      const end = new Date(product.endTime).getTime();
      const now = new Date().getTime();
      const diff = end - now;

      if (diff <= 0) {
        setTimeLeft('종료됨');
      } else {
        const hours = Math.floor(diff / (1000 * 60 * 60));
        const minutes = Math.floor((diff % (1000 * 60 * 60)) / (1000 * 60));
        const seconds = Math.floor((diff % (1000 * 60)) / 1000);

        if (hours > 24) {
             setTimeLeft(formatDistanceToNow(new Date(product.endTime), { addSuffix: true, locale: ko }));
        } else {
             setTimeLeft(`${hours}시간 ${minutes}분 ${seconds}초`);
        }
      }
    };

    updateTime();
    const interval = setInterval(updateTime, 1000);
    return () => clearInterval(interval);
  }, [product.endTime]);

  const isUrgent = timeLeft.includes('분') || timeLeft.includes('초') && !timeLeft.includes('시간') && !timeLeft.includes('일');

  return (
    <Link to={`/products/${product.id}`} className="group block bg-white rounded-xl shadow-sm hover:shadow-md transition-all duration-300 border border-gray-100 overflow-hidden">
      <div className="relative aspect-[4/3] overflow-hidden bg-gray-100">
        <img 
          src={product.images[0]} 
          alt={product.title} 
          className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500"
        />
        <div className="absolute top-2 right-2 bg-black/60 text-white text-xs px-2 py-1 rounded-full flex items-center backdrop-blur-sm">
          <User className="w-3 h-3 mr-1" />
          {product.participantCount}명 참여
        </div>
        {product.status === 'completed' && (
            <div className="absolute inset-0 bg-black/50 flex items-center justify-center text-white font-bold text-lg backdrop-blur-[1px]">
                판매 완료
            </div>
        )}
      </div>

      <div className="p-4">
        <div className="flex justify-between items-start mb-2">
           <h3 className="font-medium text-gray-900 line-clamp-2 min-h-[3rem]">{product.title}</h3>
        </div>

        <div className="flex justify-between items-end mt-2">
          <div>
            <p className="text-xs text-gray-500 mb-1">현재 입찰가</p>
            <p className="text-lg font-bold text-indigo-600">{product.currentPrice.toLocaleString()}원</p>
          </div>
        </div>

        <div className="mt-3 pt-3 border-t border-gray-100 flex items-center justify-between text-xs">
           <span className="text-gray-500 truncate max-w-[50%]">{product.location}</span>
           <div className={`flex items-center font-medium ${isUrgent ? 'text-red-500 animate-pulse' : 'text-gray-500'}`}>
              <Clock className="w-3.5 h-3.5 mr-1" />
              {timeLeft}
           </div>
        </div>
      </div>
    </Link>
  );
};

