export const ProductList: React.FC = () => {
  const [searchParams] = useSearchParams();
  const query = searchParams.get('q');
  const category = searchParams.get('category');

  let filteredProducts = MOCK_PRODUCTS;

  if (query) {
    filteredProducts = filteredProducts.filter(p => p.title.includes(query) || p.description.includes(query));
  }
  if (category) {
    filteredProducts = filteredProducts.filter(p => p.category === category);
  }

  return (
    <div className="container mx-auto px-4 py-8">
      <div className="flex items-center justify-between mb-8 pb-4 border-b">
         <div>
            <h2 className="text-2xl font-bold text-gray-900">
               {query ? `'${query}' 검색 결과` : category ? category : '전체 상품'}
            </h2>
            <p className="text-sm text-gray-500 mt-1">총 {filteredProducts.length}개의 상품이 있습니다.</p>
         </div>

         <div className="flex items-center space-x-2">
            <select className="border-gray-300 rounded-lg text-sm p-2 focus:ring-indigo-500 border">
               <option>최신순</option>
               <option>인기순</option>
               <option>마감 임박순</option>
               <option>높은 가격순</option>
            </select>
         </div>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-6">
         {filteredProducts.map(product => (
            <ProductCard key={product.id} product={product} />
         ))}
      </div>

      {filteredProducts.length === 0 && (
         <div className="py-20 text-center">
            <p className="text-gray-500 text-lg">검색 결과가 없습니다.</p>
         </div>
      )}

      {/* Pagination Mock */}
      {filteredProducts.length > 0 && (
         <div className="flex justify-center mt-12 space-x-2">
            <button className="w-10 h-10 flex items-center justify-center rounded-lg border border-gray-300 hover:bg-gray-50 disabled:opacity-50" disabled>&lt;</button>
            <button className="w-10 h-10 flex items-center justify-center rounded-lg bg-indigo-600 text-white font-bold">1</button>
            <button className="w-10 h-10 flex items-center justify-center rounded-lg border border-gray-300 hover:bg-gray-50">2</button>
            <button className="w-10 h-10 flex items-center justify-center rounded-lg border border-gray-300 hover:bg-gray-50">3</button>
            <button className="w-10 h-10 flex items-center justify-center rounded-lg border border-gray-300 hover:bg-gray-50">&gt;</button>
         </div>
      )}
    </div>
  );
};

